using ByteForge.Toolkit;

// Create AES encryption instance
var aes = new AESEncryption();

// Encrypt sensitive data
string plainText = "This is confidential information";
string encryptedData = aes.Encrypt(plainText);
Console.WriteLine($"Encrypted: {encryptedData}");

// Decrypt the data
string decryptedText = aes.Decrypt(encryptedData);
Console.WriteLine($"Decrypted: {decryptedText}");

// Verify the data matches
if (plainText == decryptedText)
{
    Console.WriteLine("Encryption/Decryption successful!");
}

// Generate a secure key (in practice, store this securely)
byte[] key = AESEncryption.GenerateKey();
byte[] iv = AESEncryption.GenerateIV();

var aes = new AESEncryption(key, iv);

// Encrypt multiple pieces of data with the same key
var sensitiveData = new[]
{
    "User password: mySecretPassword123",
    "Credit card: 4532-1234-5678-9012",
    "SSN: 123-45-6789"
};

var encryptedData = new List<string>();

foreach (var data in sensitiveData)
{
    var encrypted = aes.Encrypt(data);
    encryptedData.Add(encrypted);
    Console.WriteLine($"Original: {data}");
    Console.WriteLine($"Encrypted: {encrypted}");
    Console.WriteLine();
}

// Decrypt all data
Console.WriteLine("Decrypting data:");
foreach (var encrypted in encryptedData)
{
    var decrypted = aes.Decrypt(encrypted);
    Console.WriteLine($"Decrypted: {decrypted}");
}

var aes = new AESEncryption();

// Encrypt a file
string inputFile = "sensitive_document.txt";
string encryptedFile = "sensitive_document.encrypted";

try
{
    // Read original file
    string fileContent = File.ReadAllText(inputFile);
    Console.WriteLine($"Original file size: {new FileInfo(inputFile).Length} bytes");

    // Encrypt content
    string encryptedContent = aes.Encrypt(fileContent);

    // Write encrypted content to new file
    File.WriteAllText(encryptedFile, encryptedContent);
    Console.WriteLine($"Encrypted file size: {new FileInfo(encryptedFile).Length} bytes");

    // Verify by decrypting
    string readEncryptedContent = File.ReadAllText(encryptedFile);
    string decryptedContent = aes.Decrypt(readEncryptedContent);

    if (fileContent == decryptedContent)
    {
        Console.WriteLine("File encryption/decryption successful!");
    }

    // Securely delete original file if needed
    File.Delete(inputFile);
    Console.WriteLine("Original file securely deleted");
}
catch (Exception ex)
{
    Console.WriteLine($"Encryption error: {ex.Message}");
}

